import { useState } from "react";
import api from "../../api/axios";
import Input from "../../components/Input";
import { useNavigate } from "react-router-dom";

export default function Register() {
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const navigate = useNavigate();

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      await api.post("/users/register", form);
      alert("Registration successful!");
      navigate("/login");
    } catch (err) {
      alert(err.response?.data?.message || "Registration failed");
    }
  };

  return (
    <div style={{ maxWidth: "400px", margin: "50px auto" }}>
      <h2>Register</h2>
      <form onSubmit={handleSubmit}>
        <Input name="name" label="Name" value={form.name} onChange={handleChange} />
        <Input name="email" label="Email" value={form.email} onChange={handleChange} />
        <Input name="password" type="password" label="Password" value={form.password} onChange={handleChange} />
        <button type="submit" style={{ padding: "10px 20px", marginTop: "10px" }}>Register</button>
      </form>
    </div>
  );
}
